## Game Engine Integration

Finally, integrate the weather system into the main game engine:

```python
# game_engine.py
class GameEngine:
    def __init__(self):
        self.state = GameState()
        self.current_level = None
        self.player = Player()

    def load_level(self, level_data):
        """Load a level and initialize weather effects"""
        self.current_level = Level.from_data(level_data)
        self.state.update_rain_counts(self.current_level)

        # Initialize player for this level
        self.player.reset_for_level(self.current_level.weather)

    def update(self):
        """Main game update loop"""
        if self.current_level:
            # Handle player actions based on weather
            if self.player.is_gliding:
                self.player.update_glide(is_rain_level=self.current_level.weather == "rain")

    def collect_ember(self, pickup):
        """Collect ember with weather consideration"""
        return self.player.collect_ember(
            pickup, 
            is_rain_level=self.current_level.weather == "rain"
        )
```

## Balance Tracking Implementation

Add the rain level count tracking to the game:

```python
# balance_tracker.py
class BalanceTracker:
    def __init__(self):
        self.rain_counts = {
            "caverns": 0,
            "fault lines": 0,
            "hot springs": 0,
            "summit": 0
        }

    def update_from_level(self, level):
        """Update counts based on a level's weather"""
        if level.weather == "rain":
            self.rain_counts[level.region] += 1

    def get_region_rain_count(self, region_name):
        """Get rain count for a specific region"""
        return self.rain_counts.get(region_name, 0)

    def print_balance_report(self):
        """Print current balance report"""
        print("Rain Level Balance Report:")
        for region, count in self.rain_counts.items():
            print(f"  {region}: {count} rain levels")
```

